    document.documentElement.setAttribute(`data-bleh--theme`, `${current_theme}`);
    document.documentElement.setAttribute(`data-bleh--theme_type`, `${settings.theme_type}`);
    localStorage.setItem("bleh", JSON.stringify(settings));
